// Time-aware, language-aware greeting generator
const hour = new Date().getHours();
const callerName = $input.first().json.caller_name || '';
const isReturning = callerName !== '';
const lang = $input.first().json.detected_language || 'en';
const businessName = $input.first().json.business_name || 'our venue';

const greetings = {
  en: {
    morning: 'Good morning',
    afternoon: 'Good afternoon',
    evening: 'Good evening'
  },
  ta: {
    morning: 'காலை வணக்கம்',
    afternoon: 'மதிய வணக்கம்',
    evening: 'மாலை வணக்கம்'
  },
  te: {
    morning: 'శుభోదయం',
    afternoon: 'శుభ మధ్యాహ్నం',
    evening: 'శుభ సాయంత్రం'
  },
  kn: {
    morning: 'ಶುಭೋದಯ',
    afternoon: 'ಶುಭ ಮಧ್ಯಾಹ್ನ',
    evening: 'ಶುಭ ಸಂಜೆ'
  },
  ml: {
    morning: 'സുപ്രഭാതം',
    afternoon: 'ശുഭ ഉച്ചയ്ക്ക്',
    evening: 'ശുഭ സന്ധ്യ'
  }
};

let timeSlot = 'morning';
if (hour >= 12 && hour < 17) timeSlot = 'afternoon';
if (hour >= 17) timeSlot = 'evening';

const greeting = (greetings[lang] || greetings.en)[timeSlot];

let message;
if (isReturning) {
  message = `${greeting}! Welcome back ${callerName}! This is ${businessName}. How can I help you today?`;
} else {
  message = `${greeting}! Thank you for calling ${businessName}. My name is Priya. How may I assist you?`;
}

return [{ json: { ...$input.first().json, greeting_message: message, greeting_lang: lang } }];

const turnCount = parseInt($input.first().json.turn_count) || 0;
const silenceCount = parseInt($input.first().json.silence_count) || 0;
const newSilenceCount = silenceCount + 1;

let response;
if (newSilenceCount === 1) {
  response = "I didn't quite catch that. Could you please repeat?";
} else if (newSilenceCount === 2) {
  response = "Hello? Are you still there? I'm here to help whenever you're ready.";
} else {
  response = "It seems like we're having trouble hearing each other. I'll send you a WhatsApp message so you can reach us easily. Thank you for calling!";
}

return [{ json: { 
  ...($input.first().json), 
  ai_response: response, 
  silence_count: newSilenceCount,
  should_end_call: newSilenceCount >= 3
}}];

const transcript = $input.first().json.results.channels[0].alternatives[0].transcript;
const detectedLang = $input.first().json.results.channels[0].detected_language;
const confidence = $input.first().json.results.channels[0].alternatives[0].confidence;
const sessionLang = $input.first().json.detected_language;
const turnCount = parseInt($input.first().json.turn_count) || 0;

// Language mapping
const langMap = {
  'ta': 'tamil', 'ta-IN': 'tamil',
  'te': 'telugu', 'te-IN': 'telugu',
  'kn': 'kannada', 'kn-IN': 'kannada',
  'ml': 'malayalam', 'ml-IN': 'malayalam',
  'en': 'english', 'en-IN': 'english', 'en-US': 'english'
};

let finalLang = sessionLang;

// Only update language in first 2 turns or if session is still 'auto'
if (turnCount <= 2 || sessionLang === 'auto') {
  if (confidence > 0.7 && langMap[detectedLang]) {
    finalLang = detectedLang.split('-')[0]; // normalize to 2-char code
  } else {
    finalLang = 'en'; // default to English
  }
}

return [{ json: {
  ...($input.first().json),
  caller_transcript: transcript,
  detected_language: finalLang,
  language_name: langMap[finalLang] || 'english',
  stt_confidence: confidence,
  turn_count: turnCount + 1
}}];

const transcript = $input.first().json.caller_transcript;
const lower = transcript.toLowerCase();

// Keyword-based emotion signals
const angerKeywords = ['worst', 'terrible', 'disgusting', 'pathetic', 'waste', 'cheat', 'fraud', 'angry', 'disappointed', 'unacceptable', 'ridiculous', 'horrible', 'damn', 'hell'];
const urgencyKeywords = ['urgent', 'immediately', 'right now', 'emergency', 'asap', 'hurry', 'quickly', 'fast', 'tonight', 'today only'];
const confusionKeywords = ['confused', 'don\'t understand', 'what do you mean', 'unclear', 'not sure', 'which one', 'huh', 'sorry what'];
const happyKeywords = ['great', 'awesome', 'perfect', 'wonderful', 'amazing', 'excellent', 'fantastic', 'love it', 'thank you so much'];
const escalationKeywords = ['manager', 'supervisor', 'human', 'real person', 'transfer', 'speak to someone', 'complaint'];

let emotion = 'neutral';
let escalate = false;
let confidence = 0.5;

if (angerKeywords.some(k => lower.includes(k))) { emotion = 'angry'; confidence = 0.8; }
if (urgencyKeywords.some(k => lower.includes(k))) { emotion = 'urgent'; confidence = 0.8; }
if (confusionKeywords.some(k => lower.includes(k))) { emotion = 'confused'; confidence = 0.7; }
if (happyKeywords.some(k => lower.includes(k))) { emotion = 'happy'; confidence = 0.7; }
if (escalationKeywords.some(k => lower.includes(k))) { escalate = true; emotion = 'wants_escalation'; confidence = 0.9; }

// Exclamation marks and ALL CAPS boost anger/urgency detection
if ((transcript.match(/!/g) || []).length > 2) {
  if (emotion === 'neutral') emotion = 'frustrated';
  confidence = Math.min(confidence + 0.1, 1.0);
}

return [{ json: {
  ...($input.first().json),
  emotion_state: emotion,
  emotion_confidence: confidence,
  needs_escalation: escalate
}}];

// Generate TwiML to transfer call to human agent
const humanNumber = $input.first().json.business_config?.escalation_number || '+919876543210';
const callerName = $input.first().json.caller_name || 'A customer';

const transferMessage = "I completely understand. Let me connect you with my colleague right away. Please hold for just a moment.";

const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi">${transferMessage}</Say>
  <Dial timeout="30" callerId="${$input.first().json.business_number}">
    <Number>${humanNumber}</Number>
  </Dial>
  <Say>I'm sorry, our team member is unavailable right now. We'll call you back within 15 minutes. Thank you for your patience.</Say>
</Response>`;

return [{ json: {
  ...($input.first().json),
  twiml_response: twiml,
  escalation_triggered: true,
  escalation_reason: $input.first().json.emotion_state
}}];

// See prompts/system-prompt.md for the full system prompt
// This node assembles the complete prompt with dynamic context

const session = $input.first().json;
const history = session.conversation_history || [];
const businessConfig = session.business_config || {};

// Add current user message to history
history.push({
  role: 'user',
  content: session.caller_transcript
});

const systemPrompt = `You are Priya, a warm, professional customer care executive at ${businessConfig.business_name || 'the venue'}.

CRITICAL RULES:
- Respond in ${session.language_name || 'English'}. If the caller code-switches (e.g., Tanglish), mirror their style.
- Keep responses under 40 words for simple acknowledgments, under 80 words for detailed answers.
- Sound HUMAN. Use natural fillers: "Sure thing...", "Let me check that for you...", "Absolutely!"
- NEVER say "As an AI" or anything revealing you are not human.
- Current emotion detected: ${session.emotion_state}. Adapt your tone accordingly:
  - angry → empathetic, calm, apologetic
  - urgent → quick, efficient, reassuring
  - confused → patient, clear, step-by-step
  - happy → energetic, matching enthusiasm
  - neutral → warm, professional

BUSINESS CONTEXT:
- Name: ${businessConfig.business_name || 'N/A'}
- Type: ${businessConfig.business_type || 'restaurant/club'}
- Timings: ${businessConfig.timings || 'N/A'}
- Menu highlights: ${businessConfig.menu_highlights || 'N/A'}
- Current offers: ${businessConfig.current_offers || 'N/A'}
- VIP options: ${businessConfig.vip_options || 'N/A'}
- Address: ${businessConfig.address || 'N/A'}

CALLER CONTEXT:
- Name: ${session.caller_name || 'Unknown'}
- Returning customer: ${session.caller_name ? 'Yes' : 'No'}
- Current intent: ${session.detected_intent}
- Data collected so far: ${JSON.stringify(session.collected_data || {})}

INTENT HANDLING:
1. BOOKING: Collect date, time, number of guests, name, phone. Confirm and recap.
2. ENQUIRY: Answer from business context. If unknown, say "Let me check and get back to you."
3. COMPLAINT: Empathize first. Apologize. Offer resolution. Escalate if needed.
4. UPSELL OPPORTUNITIES: When booking, naturally suggest VIP tables, special events, or current offers. Do NOT be pushy.

DATA EXTRACTION:
After each response, output a JSON block with extracted data:
<data>{"intent": "...", "date": "...", "time": "...", "guests": ..., "name": "...", "special_requests": "..."}</data>
Only include fields that were mentioned. Use null for unknown fields.

CONVERSATION STAGE: Turn ${session.turn_count || 1}
`;

const messages = history.map(h => ({
  role: h.role,
  content: h.content
}));

return [{ json: {
  ...session,
  system_prompt: systemPrompt,
  messages: messages,
  conversation_history: history
}}];

const aiOutput = $input.first().json.content[0].text;
const session = $input.first().json;

// Extract data block if present
let extractedData = {};
const dataMatch = aiOutput.match(/<data>(.*?)<\/data>/s);
if (dataMatch) {
  try {
    extractedData = JSON.parse(dataMatch[1]);
  } catch (e) {
    extractedData = {};
  }
}

// Remove data block from spoken response
const spokenResponse = aiOutput.replace(/<data>.*?<\/data>/s, '').trim();

// Merge extracted data with existing collected data
const existingData = session.collected_data || {};
const mergedData = { ...existingData };
for (const [key, value] of Object.entries(extractedData)) {
  if (value !== null && value !== undefined && value !== '') {
    mergedData[key] = value;
  }
}

// Detect if booking is complete
const bookingComplete = mergedData.intent === 'booking' &&
  mergedData.date && mergedData.time && mergedData.guests && mergedData.name;

// Update conversation history
const history = session.conversation_history || [];
history.push({ role: 'assistant', content: spokenResponse });

return [{ json: {
  ...session,
  ai_response: spokenResponse,
  collected_data: mergedData,
  detected_intent: mergedData.intent || session.detected_intent,
  booking_complete: bookingComplete,
  conversation_history: history
}}];

const response = $input.first().json.ai_response;
const emotion = $input.first().json.emotion_state;
const turnCount = parseInt($input.first().json.turn_count) || 1;

// --- FILLER INJECTION ---
const fillers = {
  neutral: ['Sure!', 'Absolutely.', 'Of course.', 'Right.', 'Got it.'],
  thinking: ['Let me check...', 'One moment...', 'Let me see...', 'Hmm, let me look into that...'],
  empathy: ['I understand.', 'I hear you.', 'That makes sense.', 'I completely get it.']
};

let humanized = response;

// Add filler at the beginning occasionally (60% chance, not on first turn)
if (turnCount > 1 && Math.random() < 0.6) {
  let fillerSet;
  if (emotion === 'angry' || emotion === 'frustrated') {
    fillerSet = fillers.empathy;
  } else if (response.length > 100) {
    fillerSet = fillers.thinking;
  } else {
    fillerSet = fillers.neutral;
  }
  const filler = fillerSet[Math.floor(Math.random() * fillerSet.length)];
  humanized = filler + ' ' + humanized;
}

// --- SENTENCE VARIATION ---
// Avoid starting consecutive responses the same way
// (tracked via conversation history in actual deployment)

// --- PAUSE MARKERS ---
// Insert SSML pauses for natural speech rhythm
humanized = humanized.replace(/\. /g, '. <break time="300ms"/> ');
humanized = humanized.replace(/\? /g, '? <break time="400ms"/> ');
humanized = humanized.replace(/! /g, '! <break time="200ms"/> ');

// --- SPEED ADAPTATION ---
let speakRate = '1.0';
if (emotion === 'urgent') speakRate = '1.15';
if (emotion === 'angry' || emotion === 'frustrated') speakRate = '0.9';
if (emotion === 'confused') speakRate = '0.85';

// --- CALCULATE RESPONSE DELAY ---
// Simulate human thinking time (varies by response complexity)
const wordCount = response.split(' ').length;
let delayMs = Math.min(400 + (wordCount * 30), 1500); // 400ms-1500ms
if (emotion === 'urgent') delayMs = Math.max(delayMs - 300, 200);

return [{ json: {
  ...($input.first().json),
  ai_response_humanized: humanized,
  speak_rate: speakRate,
  response_delay_ms: delayMs
}}];

const audioUrl = $input.first().json.audio_url;
const shouldEndCall = $input.first().json.should_end_call || false;
const bookingComplete = $input.first().json.booking_complete || false;
const sessionId = $input.first().json.session_id;

let twiml;

if (shouldEndCall) {
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Play>${audioUrl}</Play>
  <Hangup/>
</Response>`;
} else {
  // Continue conversation: play response, then gather next input
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Play>${audioUrl}</Play>
  <Record
    maxLength="15"
    timeout="3"
    playBeep="false"
    action="/webhook/voice-agent/conversation-turn?session_id=${sessionId}"
    recordingStatusCallback="/webhook/voice-agent/recording-status"
  />
  <Say voice="Polly.Aditi">I'm still here if you need anything.</Say>
  <Record
    maxLength="15"
    timeout="5"
    playBeep="false"
    action="/webhook/voice-agent/conversation-turn?session_id=${sessionId}"
  />
</Response>`;
}

return [{ json: {
  ...($input.first().json),
  twiml_response: twiml,
  call_continuing: !shouldEndCall
}}];
